fn solve(s: String, k: i64) -> String {
    let mut result = Vec::new();
    for c in s.chars() {
        match c {
            'a'..='z' => result.push(c),
            '*' => {
                if !result.is_empty() {
                    result.pop();
                }
            },
            '#' => {
                let mut temp = Vec::new();
                for ch in &result {
                    temp.push(*ch);
                }
                result.extend(temp);
            },
            '%' => {
                result.reverse();
            },
            _ => {}
        }
    }
    if k < 0 || k as usize >= result.len() {
        return String::from(".");
    }
    String::from(&result[k as usize..k as usize + 1])
}
